```

Add the MySQL Connector/J JAR (`mysql-connector-j-8.x.x.jar`) to your project's classpath.

## 3.2 Complete CRUD Program (Java)

Below is a **single, self-contained Java program** demonstrating all four CRUD operations using `PreparedStatement` and **try-with-resources**.

```java
import java.sql.*;

public class StudentDAO {
    // Database credentials — centralize for maintainability
    private static final String URL  = "jdbc:mysql://localhost:3306/studentdb";
    private static final String USER = "root";
    private static final String PASS = "password";

    // ---- CREATE: Insert a new student record ----
    public void createStudent(String name, int age, String course) 
            throws SQLException, ClassNotFoundException {

        // Step 1: Load the driver (optional in JDBC 4.0+ but explicit is better)
        Class.forName("com.mysql.cj.jdbc.Driver");

        // Step 2: SQL with placeholders (?)
        String sql = "INSERT INTO students(name, age, course) VALUES(?, ?, ?)";

        // Step 3: try-with-resources auto-closes Connection and PreparedStatement
        try (Connection con = DriverManager.getConnection(URL, USER, PASS);
             PreparedStatement pstmt = con.prepareStatement(sql)) {

            // Step 4: Bind parameters (1-indexed)
            pstmt.setString(1, name);
            pstmt.setInt(2, age);
            pstmt.setString(3, course);

            // Step 5: Execute the INSERT — returns row count
            int rows = pstmt.executeUpdate();
            System.out.println(rows + " student record(s) inserted.");
        }
    }

    // ---- READ: Fetch all students ----
    public void readStudents() 
            throws SQLException, ClassNotFoundException {

        Class.forName("com.mysql.cj.jdbc.Driver");
        String sql = "SELECT id, name, age, course FROM students";

        try (Connection con = DriverManager.getConnection(URL, USER, PASS);
             PreparedStatement pstmt = con.prepareStatement(sql);
             ResultSet rs = pstmt.executeQuery()) {

            System.out.printf("%-5s %-20s %-5s %-15s%n", 
                              "ID", "Name", "Age", "Course");
            System.out.println("------------------------------------------------");

            while (rs.next()) {
                int id     = rs.getInt("id");
                String nm  = rs.getString("name");
                int ag     = rs.getInt("age");
                String cr  = rs.getString("course");

                System.out.printf("%-5d %-20s %-5d %-15s%n", 
                                  id, nm, ag, cr);
            }
        }
    }

    // ---- UPDATE: Modify a student's course by ID ----
    public void updateStudent(int id, String newCourse) 
            throws SQLException, ClassNotFoundException {

        Class.forName("com.mysql.cj.jdbc.Driver");
        String sql = "UPDATE students SET course = ? WHERE id = ?";

        try (Connection con = DriverManager.getConnection(URL, USER, PASS);
             PreparedStatement pstmt = con.prepareStatement(sql)) {

            pstmt.setString(1, newCourse);
            pstmt.setInt(2, id);

            int rows = pstmt.executeUpdate();
            System.out.println(rows + " student record(s) updated.");
        }
    }

    // ---- DELETE: Remove a student by ID ----
    public void deleteStudent(int id) 
            throws SQLException, ClassNotFoundException {

        Class.forName("com.mysql.cj.jdbc.Driver");
        String sql = "DELETE FROM students WHERE id = ?";

        try (Connection con = DriverManager.getConnection(URL, USER, PASS);
             PreparedStatement pstmt = con.prepareStatement(sql)) {

            pstmt.setInt(1, id);

            int rows = pstmt.executeUpdate();
            System.out.println(rows + " student record(s) deleted.");
        }
    }

    // ---- MAIN: Driver program to test all CRUD methods ----
    public static void main(String[] args) {
        StudentDAO dao = new StudentDAO();
        try {
            dao.createStudent("Arjun Kumar", 21, "CSE");
            dao.createStudent("Meera Nair",   20, "IT");
            dao.readStudents();
            dao.updateStudent(1, "AIML");
            dao.deleteStudent(2);
            dao.readStudents();
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
```

### Expected Output
```
